import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as i,c as n,e}from"./app-8be5e6af.js";const t={},o=e('<h1 id="cloud-service-model" tabindex="-1"><a class="header-anchor" href="#cloud-service-model" aria-hidden="true">#</a> Cloud Service Model</h1><h2 id="云服务模式" tabindex="-1"><a class="header-anchor" href="#云服务模式" aria-hidden="true">#</a> 云服务模式</h2><figure><img src="https://pic.hanjiaming.com.cn/2024/02/29/2e4218444fc64.png" alt="1709205332804.png" tabindex="0" loading="lazy"><figcaption>1709205332804.png</figcaption></figure><ul><li>Infrastructure as a service (laas): A form of cloud computing that delivers <u>fundamental compute, network, and storage resources to consumers on-demand</u>, over the internet, and on a <strong>pay-as-you-go basis</strong>.</li><li>Platform as a service (paas): Provides customers <strong>a development and hosting platform</strong> for <u>deploying customer-created applications</u>.</li><li>Software as a service (saas): A model of software deployment where an <strong>application is hosted (in a cloud center) as a service</strong> provided to customers across the internet.</li></ul><figure><img src="https://pic.hanjiaming.com.cn/2024/02/29/9834d66a78b92.png" alt="1709206766053.png" tabindex="0" loading="lazy"><figcaption>1709206766053.png</figcaption></figure><figure><img src="https://pic.hanjiaming.com.cn/2024/02/29/ecc0128a8abc5.png" alt="1709206983587.png" tabindex="0" loading="lazy"><figcaption>1709206983587.png</figcaption></figure><figure><img src="https://pic.hanjiaming.com.cn/2024/02/29/de0c3a0836956.png" alt="1709207014300.png" tabindex="0" loading="lazy"><figcaption>1709207014300.png</figcaption></figure><ul><li>laas：亚马逊弹性计算云（ec2）、谷歌计算引擎（gce）、微软azure laas、阿里巴巴云弹性计算服务（ecs）、.NET、微软云计算服务（laas）。</li><li>Caas（laas 的另一种形式）：亚马逊弹性容器服务（ecs）、谷歌 kubernetes 引擎（gke）、docker 云、azure kubernetes 服务（aks）、腾讯 kubernetes 引擎</li><li>Paas：谷歌应用程序引擎（gae），aws 弹性beanstalk，微软azure，..</li><li>Faas（“轻量级 paas”）：aws lambda、google 云函数、azure 函数、ibm 云函数。</li></ul><img src="https://pic.hanjiaming.com.cn/2024/02/29/3d0eb441ce1dc.png" alt="1709207174763.png" style="zoom:33%;"><h2 id="iaas-virtual-machines" tabindex="-1"><a class="header-anchor" href="#iaas-virtual-machines" aria-hidden="true">#</a> IAAS-Virtual Machines</h2><p>允许不同的虚拟机（VM）共享底层物理机资源，每个虚拟机运行自己的操作系统。</p><p>虚拟化资源：虚拟CPU（vCPU）、虚拟网络接口（vNIC）、虚拟磁盘等。</p><figure><img src="https://pic.hanjiaming.com.cn/2024/03/02/15885d5a87439.png" alt="1709370535428.png" tabindex="0" loading="lazy"><figcaption>1709370535428.png</figcaption></figure><ul><li>Virtualized Network Interface (vNIC) <ul><li>看起来很像任何物理以太网 NIC。</li><li>&quot;Virtualized&quot; MAC = address MAC address &quot;assigned&quot;to vNIC (eth0)</li></ul></li><li>Use of <strong>software bridge</strong> or <strong>virtual switch</strong> to <u>emulate a hardware bridge</u></li></ul><div class="hint-container tip"><p class="hint-container-title">提示</p><p>VIF 表示虚拟机上的虚拟网卡</p></div><figure><img src="https://pic.hanjiaming.com.cn/2024/03/02/14cb7f7bb3b97.png" alt="1709371167447.png" tabindex="0" loading="lazy"><figcaption>1709371167447.png</figcaption></figure><img src="https://pic.hanjiaming.com.cn/2024/03/02/c1b37bb7524f7.png" alt="1709371354802.png" style="zoom:50%;"><figure><img src="https://pic.hanjiaming.com.cn/2024/03/02/6f4baab65b597.png" alt="CleanShot 2024-03-02 at 17.39.29@2x.png" tabindex="0" loading="lazy"><figcaption>CleanShot 2024-03-02 at 17.39.29@2x.png</figcaption></figure><h2 id="iaas-ec2" tabindex="-1"><a class="header-anchor" href="#iaas-ec2" aria-hidden="true">#</a> IAAS-EC2</h2><figure><img src="https://pic.hanjiaming.com.cn/2024/03/02/0adb3f6a10d42.png" alt="1709385334702.png" tabindex="0" loading="lazy"><figcaption>1709385334702.png</figcaption></figure><ul><li>An AWS EC2 Instance is nothing but a virtual machine in the AWS cloud「An AWS EC2 Instance is nothing but a virtual machine in the AWS cloud」</li><li>Amazon Machine Image (AMI) = preconfigured server templates, which 提供启动 EC2 实例所需的信息</li></ul><p>Choose an Amazon Machine Image (AMI):</p><ul><li>Instance type:small,medium,micro,large,.</li><li>Operating system:Linux,Windows...</li><li>Architecture 32-bit or 64-bit</li><li>Region:Asia Pacific,US,EU,</li><li>Launch permissions:public/explicit/implicit</li><li>Storage for the Root Device</li></ul><figure><img src="https://pic.hanjiaming.com.cn/2024/03/02/3bbb3b3ec7159.png" alt="1709385791175.png" tabindex="0" loading="lazy"><figcaption>1709385791175.png</figcaption></figure><h2 id="caas" tabindex="-1"><a class="header-anchor" href="#caas" aria-hidden="true">#</a> CAAS</h2><h3 id="container-technologies" tabindex="-1"><a class="header-anchor" href="#container-technologies" aria-hidden="true">#</a> Container Technologies</h3><p>容器位于物理服务器及其主机操作系统（通常为 Linux 或 Windows）之上。前言：谷歌使用容器运行几乎所有谷歌应用程序（如 Gmail、YouTube）</p><figure><img src="https://pic.hanjiaming.com.cn/2024/03/02/91279318df7e3.png" alt="1709385959549.png" tabindex="0" loading="lazy"><figcaption>1709385959549.png</figcaption></figure><p>A “container” = a virtualized server</p><p>CaaS typically refers to a complete container environment「完整的容器环境」,including orchestration tools「编排工具」 (e.g.,Kubernetes), an image catalog「镜像目录」 (Registry), cluster management software 「集群管理软件」,and a set of developer tools and APls.</p><h3 id="container-orchestration" tabindex="-1"><a class="header-anchor" href="#container-orchestration" aria-hidden="true">#</a> Container Orchestration</h3><p>容器协调器：实现容器生命周期管理自动化（创建/终止、资源分配、联网、自动扩展、故障恢复......）。</p><figure><img src="https://pic.hanjiaming.com.cn/2024/03/02/af51ab620912e.png" alt="1709386324568.png" tabindex="0" loading="lazy"><figcaption>1709386324568.png</figcaption></figure><p>Tasks done by Container Orchestration</p><ul><li>Provisioning「调配」 and deployment「部署」 of s containers</li><li>Redundancy「冗余」 and availability「可用性」 of containers</li><li>扩展或移除容器，以便在主机基础设施上均匀分布应用程序负载</li><li>在主机资源短缺或主机死亡的情况下，将容器从一台主机转移到另一台主机</li><li>Allocation of resources between containers</li><li>Load balancing between containers</li><li>Health monitoring of containers and hosts</li><li>Configuration of an application in relation to the containers running it</li></ul><img src="https://pic.hanjiaming.com.cn/2024/03/02/dfa935fcc8b6d.png" alt="1709387020971.png" style="zoom:50%;"><h2 id="paas" tabindex="-1"><a class="header-anchor" href="#paas" aria-hidden="true">#</a> PAAS</h2><p>云提供商为那些想创建服务但又不想构建自己的云基础设施的开发人员提供了一个基于互联网的平台。</p><ul><li>目标用户: 云服务/应用程序开发人员</li><li>“基于互联网的平台”：托管在云提供商基础设施上的一组基于网络的开发工具。</li></ul><p>客户通过所提供的 APl 与平台进行交互（如编译、调试和部署）。</p><p>客户只需处理数据和应用程序，其余各层（如虚拟机/容器、软件）的管理则由 PaaS 服务提供商负责。</p><div class="hint-container tip"><p class="hint-container-title">PaaS Example: Amazon Elastic Beanstalk</p><p>You simply upload your application,and AEB automatically handles the deployment from capacity provisioning「容量配置」,load balancing 「负载均衡」,scaling「缩放」, and application health monitoring.</p></div><figure><img src="https://pic.hanjiaming.com.cn/2024/03/02/278e19b154b9b.png" alt="1709387746233.png" tabindex="0" loading="lazy"><figcaption>1709387746233.png</figcaption></figure><h2 id="faas" tabindex="-1"><a class="header-anchor" href="#faas" aria-hidden="true">#</a> FaaS</h2>',44),c=[o];function r(l,s){return i(),n("div",null,c)}const d=a(t,[["render",r],["__file","csm.html.vue"]]);export{d as default};
